from collections import deque
class Solution:
    def collectTheCoins(self, coins, edges):
        n = len(coins)
        if n <= 1:
            return 0
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        coin_nodes = [i for i in range(n) if coins[i] == 1]
        if len(coin_nodes) <= 1:
            return 0
        needed = set()
        def bfs_path(src, dst):
            parent = {src: None}
            q = deque([src])
            while q:
                u = q.popleft()
                if u == dst:
                    break
                for v in adj[u]:
                    if v not in parent:
                        parent[v] = u
                        q.append(v)
            path = []
            cur = dst
            while cur is not None:
                path.append(cur)
                cur = parent[cur]
            return path
        for i in range(len(coin_nodes)):
            for j in range(i + 1, len(coin_nodes)):
                needed.update(bfs_path(coin_nodes[i], coin_nodes[j]))
        for _ in range(2):
            deg = {u: sum(1 for v in adj[u] if v in needed) for u in needed}
            leaves = [u for u in needed if deg[u] <= 1]
            for u in leaves:
                needed.discard(u)
        remaining_edges = 0
        for u in needed:
            for v in adj[u]:
                if v in needed:
                    remaining_edges += 1
        return (remaining_edges // 2) * 2

