from collections import deque, defaultdict
class Solution:
    def collectTheCoins(self, coins, edges):
        n = len(coins)
        if n <= 1:
            return 0
        adj = defaultdict(set)
        for a, b in edges:
            adj[a].add(b)
            adj[b].add(a)
        degree = [len(adj[i]) for i in range(n)]
        removed = [False] * n
        queue = deque(i for i in range(n) if degree[i] == 1 and coins[i] == 0)
        while queue:
            u = queue.popleft()
            if removed[u]:
                continue
            removed[u] = True
            for v in adj[u]:
                if not removed[v]:
                    degree[v] -= 1
                    if degree[v] == 1 and coins[v] == 0:
                        queue.append(v)
        for _ in range(2):
            leaves = [i for i in range(n) if not removed[i] and degree[i] == 1]
            for u in leaves:
                if removed[u]:
                    continue
                removed[u] = True
                for v in adj[u]:
                    if not removed[v]:
                        degree[v] -= 1
        remaining_edges = 0
        for i in range(n):
            if not removed[i]:
                for j in adj[i]:
                    if not removed[j]:
                        remaining_edges += 1
        return (remaining_edges // 2) * 2

