var collectTheCoins = function(coins, edges) {
    const n = coins.length;
    if (n <= 1) return 0;
    const adj = Array.from({ length: n }, () => new Set());
    for (const [a, b] of edges) {
        adj[a].add(b);
        adj[b].add(a);
    }
    const degree = adj.map(s => s.size);
    const removed = new Array(n).fill(false);
    const queue = [];
    for (let i = 0; i < n; i++) {
        if (degree[i] === 1 && coins[i] === 0) queue.push(i);
    }
    let head = 0;
    while (head < queue.length) {
        const u = queue[head++];
        if (removed[u]) continue;
        removed[u] = true;
        for (const v of adj[u]) {
            if (!removed[v]) {
                degree[v] -= 1;
                if (degree[v] === 1 && coins[v] === 0) queue.push(v);
            }
        }
    }
    for (let round = 0; round < 2; round++) {
        const leaves = [];
        for (let i = 0; i < n; i++) {
            if (!removed[i] && degree[i] === 1) leaves.push(i);
        }
        for (const u of leaves) {
            if (removed[u]) continue;
            removed[u] = true;
            for (const v of adj[u]) {
                if (!removed[v]) degree[v] -= 1;
            }
        }
    }
    let remainingEdges = 0;
    for (let i = 0; i < n; i++) {
        if (!removed[i]) {
            for (const j of adj[i]) {
                if (!removed[j]) remainingEdges++;
            }
        }
    }
    return Math.floor(remainingEdges / 2) * 2;
};
